  "Description.UsernameChangeEmail.From":
    "{escapeLiteralStart}Modifica nome utente Roblox{escapeLiteralEnd} {fromEmailAddress}",
  "Description.VerificationEmail.From.Under13":
    "{escapeLiteratStart}Autorizzazione account Roblox{escapeLiteralEnd} {fromEmailAddress}",
